age errorPage=&quot;error/500.jsp&quot; %&gt;--%&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;% int x = 1/0;%&gt;&lt;/body&gt;&lt;/html&gt; 4.JSP指令12345678910111213141516171819&lt;%@page args.... %&gt;&lt;%@include file=&quot;&quot;%&gt;&lt;%--@include会将两个页面合二为一--%&gt;&lt;%@include file=&quot;common/header.jsp&quot;%&gt;&lt;h1&gt;网页主体&lt;/h1&gt;&lt;%@include file=&quot;common/footer.jsp&quot;%&gt;&lt;hr&gt;&lt;%--jSP标签 jsp:include：拼接页面，本质还是三个 --%&gt;&lt;jsp:include page=&quot;/common/header.jsp&quot;/&gt;&lt;h1&gt;网页主体&lt;/h1&gt;&lt;jsp:include page=&quot;/common/footer.jsp&quot;/&gt; footer.jsp 123456789&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;h1&gt;我是header&lt;/h1&gt;&lt;/body&gt;&lt;/html&gt; header.jsp 123456789&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;h1&gt;我是header&lt;/h1&gt;&lt;/body&gt;&lt;/html&gt; jsp3.jsp 123456789101112131415&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt; &lt;%@include file=&quot;common/header.jsp&quot;%&gt; &lt;h1&gt;网页主体&lt;/h1&gt; &lt;%@include file=&quot;common/footer.jsp&quot;%&gt; &lt;jsp:include page=&quot;common/header.jsp&quot;/&gt; &lt;h1&gt;网页主体&lt;/h1&gt; &lt;jsp:include page=&quot;common/footer.jsp&quot;/&gt;&lt;/body&gt;&lt;/html&gt; 5.9大内置对象 PageContext 存东西 Request 存东西 Response Session 存东西 Application 【SerlvetContext】 存东西 config 【SerlvetConfig】 out page ，不用了解 exception 1234pageContext.setAttribute(&quot;name1&quot;,&quot;yty1&quot;); //保存的数据只在一个页面中有效request.setAttribute(&quot;name1&quot;,&quot;yty2&quot;);//保存的数据只在 一次请求中有效，请求转发会携带这个数据session.setAttribute(&quot;name1&quot;,&quot;yty3&quot;);//保存的数据只在一次会话中有效，从打开浏览器到关闭浏览器application.setAttribute(&quot;name1&quot;,&quot;yty4&quot;); //保存的数据只在服务器中有效，从打开服务器到关闭服务器 pageContext 123456789101112131415161718192021public void setAttribute (String name, Object attribute, int scope) &#123; switch (scope) &#123; case PAGE_SCOPE: mPage.put (name, attribute); break; case REQUEST_SCOPE: mRequest.put (name, attribute); break; case SESSION_SCOPE: mSession.put (name, attribute); break; case APPLICATION_SCOPE: mApp.put (name, attribute); break; default: throw new IllegalArgumentException (&quot;Bad scope &quot; + scope); &#125; &#125; 123pageContext.setAttribute(&quot;name1&quot;,&quot;yty1&quot;);===================等价于=======================pageContext.setAttribute(&quot;name1&quot;,&quot;yty1&quot;,1); 12345678910111213141516171819202122232425262728293031&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;%--内置对象--%&gt;&lt;% pageContext.setAttribute(&quot;name1&quot;,&quot;yty1&quot;); request.setAttribute(&quot;name2&quot;,&quot;yty2&quot;); session.setAttribute(&quot;name3&quot;,&quot;yty3&quot;); application.setAttribute(&quot;name4&quot;,&quot;yty4&quot;);%&gt;&lt;% //通过pageContext取出存储的值,从低到高层查找：pageContext-&gt;request-&gt;session-&gt;application String name1 = (String) pageContext.findAttribute(&quot;name1&quot;); String name2 = (String) pageContext.findAttribute(&quot;name2&quot;); String name3 = (String) pageContext.findAttribute(&quot;name3&quot;); String name4 = (String) pageContext.findAttribute(&quot;name4&quot;); String name5 = (String) pageContext.findAttribute(&quot;name5&quot;);%&gt;&lt;%--通过EL表达式取值输出--%&gt;&lt;h1&gt;$&#123;name1&#125;&lt;/h1&gt;&lt;h1&gt;$&#123;name2&#125;&lt;/h1&gt;&lt;h1&gt;$&#123;name3&#125;&lt;/h1&gt;&lt;h1&gt;$&#123;name4&#125;&lt;/h1&gt;&lt;h1&gt;&lt;%=name5%&gt;&lt;/h1&gt;&lt;%--null--%&gt;&lt;%--&lt;h1&gt;$&#123;name5&#125;&lt;/h1&gt;--%&gt;&lt;/body&gt;&lt;/html&gt; EL表达式与&lt;% &#x3D;%&gt;区别 123$&#123;&#125;：会自动过滤掉不存在的值&lt;%= %&gt;: 不会自动过滤掉不存在的值，如果不存在，则null request：客户端向服务器发送请求，产生的数据，用户看完就没用了，比如：新闻，用户看完没用的！ session：客户端向服务器发送请求，产生的数据，用户用完一会还有用，比如：购物车； application：客户端向服务器发送请求，产生的数据，一个用户用完了，其他用户还可能使用，比如：聊天数据； 补充 请求转发 rd.jsp 12345678910111213&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;% pageContext.forward(&quot;/index.jsp&quot;); //request.getRequestDispatcher(&quot;/index.jsp&quot;).forward(request,response);%&gt;&lt;/body&gt;&lt;/html&gt; 6.JSP标签、JSTL标签、EL表达式123456789101112&lt;!-- JSTL表达式的依赖 --&gt;&lt;dependency&gt; &lt;groupId&gt;javax.servlet.jsp.jstl&lt;/groupId&gt; &lt;artifactId&gt;jstl-api&lt;/artifactId&gt; &lt;version&gt;1.2&lt;/version&gt;&lt;/dependency&gt;&lt;!-- standard标签库 --&gt;&lt;dependency&gt; &lt;groupId&gt;taglibs&lt;/groupId&gt; &lt;artifactId&gt;standard&lt;/artifactId&gt; &lt;version&gt;1.1.2&lt;/version&gt;&lt;/dependency&gt; 6.1 EL表达式： ${ } 获取数据 执行运算 获取web开发的常用对象 调用java方法 6.2 JSP标签12345678910111213141516171819202122232425262728293031323334353637===========================jsp:include：拼接页面，本质还是三个===============================&lt;jsp:include page=&quot;common/header.jsp&quot;/&gt;&lt;h1&gt;网页主体&lt;/h1&gt;&lt;jsp:include page=&quot;common/footer.jsp&quot;/&gt;===================================jsp:forward:请求转发=====================================================================jsp:param:携带参数====================================&lt;%--jsptag.jsp--%&gt;&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;jsp:forward page=&quot;/jsptag2.jsp&quot;&gt; &lt;jsp:param name=&quot;name&quot; value=&quot;yty&quot;/&gt; &lt;jsp:param name=&quot;age&quot; value=&quot;18&quot;/&gt;&lt;/jsp:forward&gt;&lt;/body&gt;&lt;/html&gt;&lt;%--http://localhost:8080/jsptag.jsp?name=yty&amp;age=18--%&gt;&lt;%--jsptag2.jsp--%&gt;&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;%--取出参数--%&gt;name:&lt;%=request.getParameter(&quot;name&quot;)%&gt;&lt;br/&gt;age:&lt;%=request.getParameter(&quot;age&quot;)%&gt;&lt;/body&gt;&lt;/html&gt; 6.3 JSTL表达式菜鸟教程：https://www.runoob.com/jsp/jsp-jstl.html JSTL标签库的使用就是为了弥补HTML标签的不足；它自定义许多标签，可以供我们使用，标签的功能和Java代码一样！ 格式化标签 SQL标签 XML 标签 核心标签 （掌握部分） 6.4 JSTL标签库使用步骤 引入对应的 taglib 12&lt;%--引入JSTL核心标签库，才能使用JSTL标签--%&gt;&lt;%@taglib prefix=&quot;c&quot; uri=&quot;http://java.sun.com/jsp/jstl/core&quot; %&gt; 使用其中的方法 在Tomcat 也需要引入 jstl的包，否则会报错：JSTL解析错误 c：if 123456789101112131415161718192021222324252627282930313233&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;%--引入JSTL核心标签库，才能使用JSTL标签--%&gt;&lt;%@taglib prefix=&quot;c&quot; uri=&quot;http://java.sun.com/jsp/jstl/core&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;h4&gt;if测试&lt;/h4&gt;&lt;hr&gt;&lt;form action=&quot;coreif.jsp&quot; method=&quot;get&quot;&gt; &lt;%-- EL表达式获取表单中的数据 $&#123;param.参数名&#125; --%&gt; &lt;input type=&quot;text&quot; name=&quot;username&quot; value=&quot;$&#123;param.username&#125;&quot;&gt; &lt;input type=&quot;submit&quot; value=&quot;登录&quot;&gt;&lt;/form&gt;&lt;%--判断如果提交的用户名是管理员，则登录成功--%&gt;&lt;c:if test=&quot;$&#123;param.username.equals(&#x27;admin&#x27;)&#125;&quot; var=&quot;isAdmin&quot;&gt; &lt;c:out value=&quot;管理员欢迎您！&quot;/&gt;&lt;/c:if&gt;&lt;c:if test=&quot;$&#123;param.username.equals(&#x27;admin&#x27;)&#125;&quot; var=&quot;isAdmin&quot;&gt; &lt;c:out value=&quot;管理员欢迎您！&quot;/&gt;&lt;/c:if&gt;&lt;%--自闭合标签--%&gt;&lt;c:out value=&quot;$&#123;isAdmin&#125;&quot;/&gt;&lt;/body&gt;&lt;/html&gt; c:choose c:when c:set 12345678910111213141516171819202122232425262728&lt;%--引入JSTL核心标签库，才能使用JSTL标签--%&gt;&lt;%@taglib prefix=&quot;c&quot; uri=&quot;http://java.sun.com/jsp/jstl/core&quot; %&gt;&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;%--定义一个变量score，值为85--%&gt;&lt;c:set var=&quot;score&quot; value=&quot;55&quot;/&gt;&lt;c:choose&gt; &lt;c:when test=&quot;$&#123;score&gt;=90&#125;&quot;&gt; 你的成绩为优秀 &lt;/c:when&gt; &lt;c:when test=&quot;$&#123;score&gt;=80&#125;&quot;&gt; 你的成绩为一般 &lt;/c:when&gt; &lt;c:when test=&quot;$&#123;score&gt;=70&#125;&quot;&gt; 你的成绩为良好 &lt;/c:when&gt; &lt;c:when test=&quot;$&#123;score&lt;=60&#125;&quot;&gt; 你的成绩为不及格 &lt;/c:when&gt;&lt;/c:choose&gt;&lt;/body&gt;&lt;/html&gt; c:forEach 123456789101112131415161718192021222324252627282930313233343536373839&lt;%@ page import=&quot;java.util.ArrayList&quot; %&gt;&lt;%--引入JSTL核心标签库，才能使用JSTL标签--%&gt;&lt;%@taglib prefix=&quot;c&quot; uri=&quot;http://java.sun.com/jsp/jstl/core&quot; %&gt;&lt;%@ page contentType=&quot;text/html;charset=UTF-8&quot; language=&quot;java&quot; %&gt;&lt;html&gt;&lt;head&gt; &lt;title&gt;Title&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;% ArrayList&lt;String&gt; people = new ArrayList&lt;&gt;(); people.add(0,&quot;张三&quot;); people.add(1,&quot;李四&quot;); people.add(2,&quot;王五&quot;); people.add(3,&quot;赵六&quot;); people.add(4,&quot;田六&quot;); request.setAttribute(&quot;list&quot;,people);%&gt;&lt;%--var , 每一次遍历出来的变量items, 要遍历的对象begin, 哪里开始end, 到哪里step, 步长--%&gt;&lt;c:forEach var=&quot;people&quot; items=&quot;$&#123;list&#125;&quot;&gt; &lt;c:out value=&quot;$&#123;people&#125;&quot;/&gt; &lt;br&gt;&lt;/c:forEach&gt;&lt;hr&gt;&lt;c:forEach var=&quot;people&quot; items=&quot;$&#123;list&#125;&quot; begin=&quot;1&quot; end=&quot;3&quot; step=&quot;1&quot; &gt; &lt;c:out value=&quot;$&#123;people&#125;&quot;/&gt; &lt;br&gt;&lt;/c:forEach&gt;&lt;/body&gt;&lt;/html&gt;
